using System;

class Methods
{
  static void Main(string[] args)
  {
    Console.WriteLine(Add(5, 3));
  }

  static Add(int a, int b)
  {
    return a + b;
  }

  static Greet(string name)
  {
    Console.WriteLine($"Hello, {name}!");
  }

  static IsEven(int n)
  {
    return n % 2 == 0;
  }
}
